+            first: 1,
+            last: 5,
+            width: 2,
+        };
+        assert_eq!(a, b);
+    }
+
+    #[test]
+    fn cellwidth_inequality() {
+        let a = CellWidth {
+            first: 1,
+            last: 5,
+            width: 2,
+        };
+        let b = CellWidth {
+            first: 1,
+            last: 5,
+            width: 1,
+        };
+        assert_ne!(a, b);
+    }
+}

